    "install:all": "npm run install:root && npm run install:webapp",
    "build:webapp": "npm --prefix webapp run build",
    "build": "npm run install:root && npm run install:webapp && npm run build:webapp",
    "start": "node src/index.js",
    "dev": "node --watch src/index.js",
    "dev:webapp": "npm --prefix webapp run dev"
  },
  "dependencies": {
    "dotenv": "^16.4.5",
    "grammy": "^1.20.0",
    "express": "latest",
