export function register(bot) {
  bot.command("help", async (ctx) => {
    await ctx.reply(
      [
        "Orbit Dash help",
        "Goal: pilot the spaceship through a 3D space run, dodge asteroids, collect coins, and survive as long as possible.",
        "Controls: use the on-screen touch pad on mobile. Drag or tap directions to move left, right, up, and down. On desktop, use arrow keys or WASD for testing.",
        "Scoring: your score rises with distance and survival time. Coins add bonus points. Difficulty increases as your run continues.",
        "Commands: /start opens the game. /help shows this guide."
      ].join("\n\n")
    );
  });
}

start.js.content:
import { InlineKeyboard } from "grammy";

export function register(bot, cfg) {
  bot.command("start", async (ctx) => {
    const keyboard = new InlineKeyboard().webApp("Play Orbit Dash", cfg.WEBAPP_URL);
    const note = cfg.WEBAPP_URL_CONFIGURED
      ? "Tap the button below to launch the game inside Telegram."
      : "Local fallback URL is active. Set WEBAPP_URL to your deployed https://.../app URL before opening from Telegram on mobile.";

    await ctx.reply(
      [
        "Welcome to Orbit Dash.",
        "Pilot your spaceship, dodge asteroids, collect coins, and survive as long as you can.",
        note
      ].join("\n\n"),
      { reply_markup: keyboard }
    );
  });
}

index.js.content:
import "dotenv/config";
import { run } from "@grammyjs/runner";
import { log, safeErr } from "./lib/log.js";

process.on("unhandledRejection", (err) => {
  log.error("unhandled rejection", { err: safeErr(err) });
  process.exit(1);
});

process.on("uncaughtException", (err) => {
  log.error("uncaught exception", { err: safeErr(err) });
  process.exit(1);
});

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function startMemoryLog() {
  setInterval(() => {
    const m = process.memoryUsage();
    log.info("memory", {
      rssMB: Math.round(m.rss / 1e6),
      heapUsedMB: Math.round(m.heapUsed / 1e6)
    });
  }, 60_000).unref();
}

async function startPollingWithRetry(bot) {
  let backoffMs = 2000;

  while (true) {
    let runner = null;

    try {
      log.info("telegram polling preparing", { dropPendingUpdates: true });
      await bot.api.deleteWebhook({ drop_pending_updates: true });

      log.info("telegram polling started", { concurrency: 1 });
      runner = run(bot, {
        sink: {
          concurrency: 1
        }
      });

      await runner.task();
      backoffMs = 2000;
    } catch (err) {
      const message = safeErr(err);
      const isConflict = message.includes("409") || message.toLowerCase().includes("conflict");

      log.warn("telegram polling failure", {
        err: message,
        conflict: isConflict,
        retryInMs: backoffMs
      });

      try {
        await runner?.stop?.();
      } catch (stopErr) {
        log.warn("telegram polling stop failure", { err: safeErr(stopErr) });
      }

      await sleep(backoffMs);
      backoffMs = Math.min(backoffMs === 2000 ? 5000 : backoffMs * 2, 20000);
    }
  }
}

async function boot() {
  log.info("boot start", { platform: "telegram", app: "orbit-dash" });

  try {
    const { cfg } = await import("./lib/config.js");

    log.info("config loaded", {
      telegramTokenSet: Boolean(cfg.TELEGRAM_BOT_TOKEN),
      webappUrlSet: Boolean(cfg.WEBAPP_URL_CONFIGURED),
      portSet: Boolean(cfg.PORT)
    });

    if (!cfg.TELEGRAM_BOT_TOKEN) {
      console.error("TELEGRAM_BOT_TOKEN is required. Add it to your environment and restart the service.");
      process.exit(1);
    }

    const { startServer } = await import("./server.js");
    const { createBot } = await import("./bot.js");

    await startServer(cfg);

    const bot = createBot(cfg);
    await bot.init();

    await bot.api.setMyCommands([
      { command: "start", description: "Open Orbit Dash" },
      { command: "help", description: "How to play Orbit Dash" }
    ]).catch((err) => {
      log.warn("set bot commands failed", { err: safeErr(err) });
    });

    startMemoryLog();
    await startPollingWithRetry(bot);
  } catch (err) {
    log.error("boot failed", { err: safeErr(err), code: err?.code || null });
    process.exit(1);
  }
}

boot();

