export function buildBotProfile(cfg) {
  const urlState = cfg.WEBAPP_URL_CONFIGURED ? "configured" : "using local development fallback";

  return [
    "Orbit Dash is a Telegram-only Mini App game where players pilot a spaceship, dodge asteroids, collect coins, and survive as long as possible.",
    "Public commands: /start opens the game with a Telegram Web App button. /help explains the objective, controls, scoring, and restart flow.",
    `Features: hosted game at /app, mobile touch controls, desktop keyboard testing, score, coins, survival timer, and local high score persistence. Web App URL is ${urlState}.`,
    "Key rules: this bot only supports Telegram, runs the bot and game web server in one Node.js process, and does not expose admin actions."
  ].join("\n");
}

config.js.content:
function cleanUrl(value) {
  return String(value || "").replace(/\/+$/, "");
}

const port = Number(process.env.PORT || 3000);
const explicitWebAppUrl = cleanUrl(process.env.WEBAPP_URL || "");
const renderBase = cleanUrl(process.env.RENDER_EXTERNAL_URL || "");
const fallbackLocalUrl = `http://localhost:${port}/app`;

export const cfg = {
  TELEGRAM_BOT_TOKEN: process.env.TELEGRAM_BOT_TOKEN || "",
  WEBAPP_URL: explicitWebAppUrl || (renderBase ? `${renderBase}/app` : fallbackLocalUrl),
  WEBAPP_URL_CONFIGURED: Boolean(explicitWebAppUrl || renderBase),
  PORT: Number.isFinite(port) && port > 0 ? port : 3000
};

log.js.content:
export function safeErr(err) {
  return err?.response?.data?.error?.message ||
    err?.response?.data?.message ||
    err?.message ||
    String(err);
}

export const log = {
  info(message, meta = {}) {
    console.log(JSON.stringify({ level: "info", message, ...meta }));
  },
  warn(message, meta = {}) {
    console.warn(JSON.stringify({ level: "warn", message, ...meta }));
  },
  error(message, meta = {}) {
    console.error(JSON.stringify({ level: "error", message, ...meta }));
  }
};

server.js.content:
import express from "express";
import path from "node:path";
import fs from "node:fs";
import { fileURLToPath } from "node:url";
import { log, safeErr } from "./lib/log.js";

const currentDir = path.dirname(fileURLToPath(import.meta.url));

export async function startServer(cfg) {
  const app = express();
  app.disable("x-powered-by");
  app.use(express.json({ limit: "128kb" }));

  app.get("/health", (_req, res) => {
    res.json({ ok: true, app: "orbit-dash", webapp: "/app" });
  });

  app.post("/api/miniapp/ping", (_req, res) => {
    res.json({ ok: true, ts: Date.now() });
  });

  const distDir = path.join(currentDir, "..", "webapp", "dist");
  const indexHtml = path.join(distDir, "index.html");

  function sendIndex(_req, res) {
    if (fs.existsSync(indexHtml)) {
      return res.sendFile(indexHtml);
    }

    return res.status(200).send(
      "Orbit Dash web app is not built yet. Run npm run build:webapp, then start the server again."
    );
  }

  if (fs.existsSync(distDir)) {
    app.use("/app", express.static(distDir, {
      index: false,
      maxAge: "1h"
    }));
  }

  app.get("/app", sendIndex);
  app.get("/app/*splat", sendIndex);
  app.get("/", (_req, res) => res.redirect("/app"));

  const port = cfg.PORT || 3000;

  await new Promise((resolve, reject) => {
    const server = app.listen(port, () => resolve(server));
    server.on("error", reject);
  }).catch((err) => {
    log.error("web server startup failure", { err: safeErr(err), port });
    throw err;
  });

  log.info("web server started", {
    port,
    appPath: "/app",
    webappUrlSet: Boolean(cfg.WEBAPP_URL_CONFIGURED)
  });
}

App.jsx.content:
import { useEffect, useMemo, useRef, useState } from "react";
import { createOrbitDashGame, hasWebGL } from "./game/OrbitDashGame.js";

const bestKey = "orbitDash.bestScore";
const coinsKey = "orbitDash.totalCoins";

function readNumber(key) {
  const value = Number(localStorage.getItem(key) || 0);
  return Number.isFinite(value) ? value : 0;
}

function haptic(type = "light") {
  const feedback = window.Telegram?.WebApp?.HapticFeedback;
  try {
    if (type === "success" || type === "warning" || type === "error") {
      feedback?.notificationOccurred?.(type);
    } else {
      feedback?.impactOccurred?.(type);
    }
  } catch {}
}

export function App() {
  const mountRef = useRef(null);
  const gameRef = useRef(null);
  const [screen, setScreen] = useState("empty");
  const [stats, setStats] = useState({ score: 0, coins: 0, survival: 0, level: 1, energy: 100 });
  const [finalStats, setFinalStats] = useState(null);
  const [error, setError] = useState("");
  const [bestScore, setBestScore] = useState(() => readNumber(bestKey));
  const [totalCoins, setTotalCoins] = useState(() => readNumber(coinsKey));

  const statusText = useMemo(() => {
    if (screen === "loading") return "Calibrating engines...";
    if (screen === "empty") return "Waiting to initialize...";
    if (screen === "playing") return "Swipe or tap controls to dodge.";
    if (screen === "gameover") return "Run complete. Ready for another orbit.";
    return "Ready for launch.";
  }, [screen]);

  useEffect(() => {
    let disposed = false;
    setScreen("loading");

    const timer = window.setTimeout(() => {
      try {
        if (!hasWebGL()) {
          throw new Error("WebGL is not available in this WebView. Update Telegram or try another device.");
        }

        if (disposed || !mountRef.current) return;

        gameRef.current = createOrbitDashGame(mountRef.current, {
          onReady: () => setScreen("ready"),
          onUpdate: (nextStats) => setStats(nextStats),
          onGameOver: (result) => {
            haptic("error");
            setFinalStats(result);
            setScreen("gameover");

            const nextBest = Math.max(readNumber(bestKey), result.score);
            const nextCoins = readNumber(coinsKey) + result.coins;
            localStorage.setItem(bestKey, String(nextBest));
            localStorage.setItem(coinsKey, String(nextCoins));
            setBestScore(nextBest);
            setTotalCoins(nextCoins);
          },
          onError: (message) => {
            setError(message);
            setScreen("error");
          }
        });
      } catch (err) {
        setError(err?.message || "Orbit Dash could not start in this WebView.");
        setScreen("error");
      }
    }, 250);

    return () => {
      disposed = true;
      window.clearTimeout(timer);
      gameRef.current?.destroy?.();
      gameRef.current = null;
    };
  }, []);

  function play() {
    haptic("success");
    setFinalStats(null);
    setStats({ score: 0, coins: 0, survival: 0, level: 1, energy: 100 });
    setScreen("playing");
    gameRef.current?.restart?.();
  }

  function retryInit() {
    window.location.reload();
  }

  function move(dx, dy) {
    gameRef.current?.move?.(dx, dy);
  }

  return (
    <main className="relative h-dvh w-screen overflow-hidden bg-[#050816] text-white">
      <div className="starfield" />
      <section ref={mountRef} className="absolute inset-0" aria-label="Orbit Dash 3D game viewport" />

      <div className="pointer-events-none absolute inset-x-0 top-0 z-20 flex items-start justify-between gap-3 px-4 pt-safeTop">
        <div className="hud-card">
          <span>Score</span>
          <strong>{stats.score}</strong>
        </div>
        <div className="hud-card">
          <span>Coins</span>
          <strong>{stats.coins}</strong>
        </div>
        <div className="hud-card">
          <span>Time</span>
          <strong>{stats.survival}s</strong>
        </div>
      </div>

      {screen === "playing" && (
        <div className="pointer-events-none absolute inset-x-0 bottom-0 z-30 px-4 pb-safeBottom">
          <div className="mx-auto mb-3 flex max-w-md items-center justify-between rounded-3xl border border-white/10 bg-black/30 p-3 text-xs text-white/80 shadow-2xl backdrop-blur-xl">
            <span>Level {stats.level}</span>
            <span>Energy {stats.energy}%</span>
            <span>Drag anywhere</span>
          </div>
          <div className="pointer-events-auto mx-auto grid max-w-sm grid-cols-3 gap-3 rounded-[2rem] border border-white/10 bg-black/35 p-4 shadow-2xl backdrop-blur-xl">
            <button className="control-btn col-start-2" onPointerDown={() => move(0, -1)} onPointerUp={() => move(0, 0)}>Up</button>
            <button className="control-btn" onPointerDown={() => move(-1, 0)} onPointerUp={() => move(0, 0)}>Left</button>
            <button className="control-btn" onPointerDown={() => move(0, 1)} onPointerUp={() => move(0, 0)}>Down</button>
            <button className="control-btn" onPointerDown={() => move(1, 0)} onPointerUp={() => move(0, 0)}>Right</button>
          </div>
        </div>
      )}

      {screen !== "playing" && (
        <div className="absolute inset-0 z-40 grid place-items-center px-4 py-safeY">
          <div className="panel w-full max-w-md text-center">
            {(screen === "empty" || screen === "loading") && (
              <>
                <div className="mx-auto mb-5 h-14 w-14 animate-pulse rounded-2xl bg-cyan-300/20 ring-1 ring-cyan-200/30" />
                <p className="text-sm uppercase tracking-[0.35em] text-cyan-200/80">Orbit Dash</p>
                <h1 className="mt-3 text-4xl font-black tracking-tight">Loading Runway</h1>
                <p className="mt-4 text-base text-white/70">{statusText}</p>
              </>
            )}

            {screen === "ready" && (
              <>
                <p className="text-sm uppercase tracking-[0.35em] text-cyan-200/80">Telegram Space Runner</p>
                <h1 className="mt-3 text-5xl font-black tracking-tight">Orbit Dash</h1>
                <p className="mt-4 text-base leading-7 text-white/75">
                  Pilot a neon ship through asteroid lanes, collect coins, build energy boosts, and survive the rising speed.
                </p>
                <div className="mt-6 grid grid-cols-2 gap-3 text-left">
                  <div className="mini-card"><span>Best</span><strong>{bestScore}</strong></div>
                  <div className="mini-card"><span>Total Coins</span><strong>{totalCoins}</strong></div>
                </div>
                <button className="primary-btn mt-7" onClick={play}>Play</button>
                <p className="mt-4 text-sm text-white/55">Touch controls are tuned for Telegram WebView. Keyboard works on desktop.</p>
              </>
            )}

            {screen === "gameover" && finalStats && (
              <>
                <p className="text-sm uppercase tracking-[0.35em] text-fuchsia-200/80">Game Over</p>
                <h1 className="mt-3 text-4xl font-black">Final Run</h1>
                <div className="mt-6 grid grid-cols-2 gap-3 text-left">
                  <div className="mini-card"><span>Score</span><strong>{finalStats.score}</strong></div>
                  <div className="mini-card"><span>Coins</span><strong>{finalStats.coins}</strong></div>
                  <div className="mini-card"><span>Survival</span><strong>{finalStats.survival}s</strong></div>
                  <div className="mini-card"><span>Distance</span><strong>{finalStats.distance}m</strong></div>
                </div>
                <button className="primary-btn mt-7" onClick={play}>Restart</button>
              </>
            )}

            {screen === "error" && (
              <>
                <p className="text-sm uppercase tracking-[0.35em] text-red-200/80">Engine Error</p>
                <h1 className="mt-3 text-3xl font-black">WebGL could not start</h1>
                <p className="mt-4 text-base leading-7 text-white/75">{error}</p>
                <button className="primary-btn mt-7" onClick={retryInit}>Retry</button>
              </>
            )}
          </div>
        </div>
      )}
    </main>
  );
}

OrbitDashGame.js.content:
import Phaser from "phaser";

export function hasWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(canvas.getContext("webgl") || canvas.getContext("experimental-webgl"));
  } catch {
    return false;
  }
}

const bounds = {
  x: 150,
  y: 120
};

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

class OrbitScene extends Phaser.Scene {
  constructor(callbacks, inputState) {
    super("OrbitDash");
    this.callbacks = callbacks;
    this.inputState = inputState;
  }

  preload() {
    this.createTextures();
  }

  create() {
    this.running = false;
    this.score = 0;
    this.coins = 0;
    this.survival = 0;
    this.distance = 0;
    this.level = 1;
    this.energy = 100;
    this.speed = 210;
    this.spawnTimer = 0;
    this.coinTimer = 0;
    this.boostFlash = 0;
    this.target = { x: 0, y: 0 };

    this.cameras.main.setBackgroundColor("#050816");
    this.physics.world.setBounds(-240, -180, 480, 360);

    this.add.tileSprite(0, 0, this.scale.width, this.scale.height, "stars")
      .setOrigin(0.5)
      .setScrollFactor(0)
      .setAlpha(0.9);

    this.ship = this.physics.add.sprite(0, 85, "ship");
    this.ship.setCircle(18);
    this.ship.setDepth(5);

    this.asteroids = this.physics.add.group({ allowGravity: false });
    this.coinGroup = this.physics.add.group({ allowGravity: false });

    this.physics.add.overlap(this.ship, this.asteroids, () => this.endRun());
    this.physics.add.overlap(this.ship, this.coinGroup, (_ship, coin) => this.collectCoin(coin));

    this.cursors = this.input.keyboard?.createCursorKeys();
    this.keys = this.input.keyboard?.addKeys("W,A,S,D");

    this.input.on("pointermove", (pointer) => {
      if (!this.running || !pointer.isDown) return;
      const cx = this.scale.width / 2;
      const cy = this.scale.height / 2;
      this.target.x = clamp((pointer.x - cx) * 0.95, -bounds.x, bounds.x);
      this.target.y = clamp((pointer.y - cy) * 0.75, -bounds.y, bounds.y);
    });

    this.scale.on("resize", this.handleResize, this);
    this.handleResize();
    this.callbacks.onReady?.();
  }

  createTextures() {
    const g = this.make.graphics({ x: 0, y: 0, add: false });

    g.clear();
    g.fillStyle(0x86f7ff, 1);
    g.fillTriangle(24, 0, 0, 52, 48, 52);
    g.fillStyle(0xffffff, 1);
    g.fillTriangle(24, 10, 14, 42, 34, 42);
    g.fillStyle(0x7c3aed, 1);
    g.fillTriangle(8, 48, 0, 62, 18, 52);
    g.fillTriangle(40, 48, 48, 62, 30, 52);
    g.generateTexture("ship", 48, 64);

    g.clear();
    g.fillStyle(0x8b8b98, 1);
    g.fillCircle(28, 28, 25);
    g.fillStyle(0x4b5563, 1);
    g.fillCircle(18, 20, 6);
    g.fillCircle(36, 34, 7);
    g.fillCircle(27, 43, 4);
    g.generateTexture("asteroid", 56, 56);

    g.clear();
    g.fillStyle(0xfacc15, 1);
    g.fillCircle(22, 22, 20);
    g.fillStyle(0xfffbeb, 1);
    g.fillCircle(16, 15, 5);
    g.fillStyle(0xf59e0b, 1);
    g.fillCircle(22, 22, 11);
    g.generateTexture("coin", 44, 44);

    g.clear();
    g.fillStyle(0xffffff, 1);
    for (let i = 0; i < 160; i += 1) {
      g.fillCircle(Math.random() * 512, Math.random() * 512, Math.random() * 1.7 + 0.4);
    }
    g.generateTexture("stars", 512, 512);
    g.destroy();
  }

  handleResize() {
    this.cameras.main.centerOn(0, 0);
  }

  startRun() {
    this.clearObjects();
    this.running = true;
    this.score = 0;
    this.coins = 0;
    this.survival = 0;
    this.distance = 0;
    this.level = 1;
    this.energy = 100;
    this.speed = 210;
    this.spawnTimer = 0;
    this.coinTimer = 0;
    this.target = { x: 0, y: 75 };
    this.ship.setPosition(0, 85);
    this.ship.setAlpha(1);
    this.ship.setScale(1);
    this.callbacks.onUpdate?.(this.snapshot());
  }

  update(_time, deltaMs) {
    const dt = Math.min(deltaMs / 1000, 0.04);

    if (!this.running) {
      this.ship.rotation += dt * 0.8;
      return;
    }

    this.survival += dt;
    this.distance += this.speed * dt * 0.08;
    this.level = Math.max(1, Math.floor(this.survival / 12) + 1);
    this.speed = 210 + this.level * 24 + this.survival * 2.2;
    this.score = Math.floor(this.distance * 2 + this.coins * 125);
    this.energy = clamp(Math.round(100 - this.level * 4 + this.coins * 2), 18, 100);

    this.updateInput(dt);
    this.updateObjects(dt);
    this.spawnTimer -= dt;
    this.coinTimer -= dt;

    if (this.spawnTimer <= 0) {
      this.spawnAsteroid();
      this.spawnTimer = clamp(1.1 - this.level * 0.055, 0.42, 1.1);
    }

    if (this.coinTimer <= 0) {
      this.spawnCoin();
      this.coinTimer = clamp(1.45 - this.level * 0.035, 0.7, 1.45);
    }

    this.ship.rotation = Phaser.Math.Linear(this.ship.rotation, (this.target.x - this.ship.x) / 180, 0.16);
    this.callbacks.onUpdate?.(this.snapshot());
  }

  updateInput(dt) {
    const keyboardSpeed = 230 * dt;

    if (this.cursors?.left?.isDown || this.keys?.A?.isDown) this.target.x -= keyboardSpeed;
    if (this.cursors?.right?.isDown || this.keys?.D?.isDown) this.target.x += keyboardSpeed;
    if (this.cursors?.up?.isDown || this.keys?.W?.isDown) this.target.y -= keyboardSpeed;
    if (this.cursors?.down?.isDown || this.keys?.S?.isDown) this.target.y += keyboardSpeed;

    this.target.x += this.inputState.dx * 260 * dt;
    this.target.y += this.inputState.dy * 220 * dt;

    this.target.x = clamp(this.target.x, -bounds.x, bounds.x);
    this.target.y = clamp(this.target.y, -bounds.y, bounds.y);

    this.ship.x = Phaser.Math.Linear(this.ship.x, this.target.x, 0.23);
    this.ship.y = Phaser.Math.Linear(this.ship.y, this.target.y, 0.23);
  }

  updateObjects(dt) {
    const drift = this.speed * dt;

    this.asteroids.children.iterate((asteroid) => {
      if (!asteroid) return;
      asteroid.y += drift;
      asteroid.rotation += dt * asteroid.getData("spin");
      asteroid.scale = Phaser.Math.Linear(asteroid.scale, 1.25, 0.01);
      if (asteroid.y > this.scale.height / 2 + 90) asteroid.destroy();
    });

    this.coinGroup.children.iterate((coin) => {
      if (!coin) return;
      coin.y += drift * 0.95;
      coin.rotation += dt * 4;
      if (coin.y > this.scale.height / 2 + 90) coin.destroy();
    });
  }

  spawnAsteroid() {
    const x = Phaser.Math.Between(-bounds.x, bounds.x);
    const y = -this.scale.height / 2 - 70;
    const asteroid = this.asteroids.create(x, y, "asteroid");
    asteroid.setCircle(24);
    asteroid.setScale(Phaser.Math.FloatBetween(0.75, 1.15));
    asteroid.setData("spin", Phaser.Math.FloatBetween(-2.4, 2.4));
  }

  spawnCoin() {
    const x = Phaser.Math.Between(-bounds.x + 25, bounds.x - 25);
    const y = -this.scale.height / 2 - 80;
    const coin = this.coinGroup.create(x, y, "coin");
    coin.setCircle(18);
    coin.setScale(0.85);
  }

  collectCoin(coin) {
    coin.destroy();
    this.coins += 1;
    this.score += 125;
    this.cameras.main.flash(70, 250, 224, 90, false);
  }

  endRun() {
    if (!this.running) return;
    this.running = false;
    this.ship.setAlpha(0.35);
    this.cameras.main.shake(180, 0.01);
    this.callbacks.onGameOver?.({
      score: Math.max(0, this.score),
      coins: this.coins,
      survival: Math.floor(this.survival),
      distance: Math.floor(this.distance)
    });
  }

  clearObjects() {
    this.asteroids?.clear(true, true);
    this.coinGroup?.clear(true, true);
  }

  snapshot() {
    return {
      score: Math.max(0, this.score),
      coins: this.coins,
      survival: Math.floor(this.survival),
      level: this.level,
      energy: this.energy
    };
  }
}

export function createOrbitDashGame(parent, callbacks) {
  const inputState = { dx: 0, dy: 0 };
  let scene = null;

  const game = new Phaser.Game({
    type: Phaser.WEBGL,
    parent,
    backgroundColor: "#050816",
    scale: {
      mode: Phaser.Scale.RESIZE,
      autoCenter: Phaser.Scale.CENTER_BOTH,
      width: parent.clientWidth || window.innerWidth,
      height: parent.clientHeight || window.innerHeight
    },
    physics: {
      default: "arcade",
      arcade: { debug: false }
    },
    scene: [new OrbitScene({
      ...callbacks,
      onReady: () => {
        scene = game.scene.getScene("OrbitDash");
        callbacks.onReady?.();
      }
    }, inputState)]
  });

  window.addEventListener("contextmenu", preventDefault, { passive: false });
  window.addEventListener("touchmove", preventDefault, { passive: false });

  return {
    restart() {
      scene?.startRun?.();
    },
    move(dx, dy) {
      inputState.dx = dx;
      inputState.dy = dy;
    },
    destroy() {
      window.removeEventListener("contextmenu", preventDefault);
      window.removeEventListener("touchmove", preventDefault);
      game.destroy(true);
    }
  };
}

function preventDefault(event) {
  event.preventDefault();
}

